INSERT INTO G_VALID (SYSTEM, VALID_ID, VALID_INDEX, VALID_TAG, VALID_NAME, VALID_REQUIRED, VALID_LENGTH, VALID_C_LENGTH, VALID_TYPE, VALID_FILTER, RSV1, RSV2, RSV3, RSV4, RSV5, VALID_OPTION) VALUES ('CIPS', 'CIPS_11201', 70044, '至少应该出现一个', null, null, null, null, 'U', 'return (valid.object.ORGNL_MSG_NM_ID ~= "cips.111.001.02" and valid.object.ORGNL_MSG_NM_ID ~= "cips.112.001.02") and ( (not valid.isGroupEmpty("S|IM_AGT2_ADR_DEPT|中介机构2_地址_部门")) or (not valid.isGroupEmpty("S|IM_AGT2_ADR_SDEPT|中介机构2_地址_分部")) or (not valid.isGroupEmpty("S|IM_AGT2_ADR_STRT_NM|中介机构2_地址_街道名称")) or (not valid.isGroupEmpty("S|IM_AGT2_ADR_BLDG_NB|中介机构2_地址_建筑编号")) or (not valid.isGroupEmpty("S|IM_AGT2_ADR_BLDG_NM|中介机构2_地址_建筑名称")) or (not valid.isGroupEmpty("S|IM_AGT2_ADR_FLR|中介机构2_地址_建筑楼层")) or (not valid.isGroupEmpty("S|IM_AGT2_ADR_PST_BX|中介机构2_地址_邮政信箱")) or (not valid.isGroupEmpty("S|IM_AGT2_ADR_ROOM|中介机构2_地址_房间号")) or (not valid.isGroupEmpty("S|IM_AGT2_ADR_PST_CD|中介机构2_地址_邮政编码")) or (not valid.isGroupEmpty("S|IM_AGT2_ADR_TWN|中介机构2_地址_城镇名称")) or (not valid.isGroupEmpty("S|IM_AGT2_ADR_TWN_LOC|中介机构2_地址_城镇地址")) or (not valid.isGroupEmpty("S|IM_AGT2_ADR_DSTRCT|中介机构2_地址_地区名称")) or (not valid.isGroupEmpty("S|IM_AGT2_ADR_AREA|中介机构2_地址_国家区域（区/洲）")) or (not valid.isGroupEmpty("S|IM_AGT2_ADR_ADR_LINE1|中介机构2_地址_自由格式地址1")) or (not valid.isGroupEmpty("S|IM_AGT2_ADR_ADR_LINE2|中介机构2_地址_自由格式地址2")) )', null, null, null, null, null, 'if valid.isGroupEmpty("S|IM_AGT2_ADR_CTRY|中介机构2_地址_国家") then valid.error("当【中介机构2_地址_部门、中介机构2_地址_分部、中介机构2_地址_街道名称、中介机构2_地址_建筑编号、中介机构2_地址_建筑名称、中介机构2_地址_建筑楼层、中介机构2_地址_邮政信箱、中介机构2_地址_房间号、中介机构2_地址_邮政编码、中介机构2_地址_城镇名称、中介机构2_地址_城镇地址、中介机构2_地址_地区名称、中介机构2_地址_国家区域（区/洲）、中介机构2_地址_自由格式地址2、中介机构2_地址_自由格式地址2】下的节点有值时，【中介机构2_地址_国家】下也应该有节点出现") return false end
